'use client'
import { cn, createMachine, useMachine, useSignals } from '@cascivo/core'
import type { InputHTMLAttributes } from 'react'
import styles from './time-picker.module.css'

const machine = createMachine({
  initial: 'idle' as const,
  states: {
    idle: { on: { FOCUS: 'focused' } },
    focused: { on: { BLUR: 'idle' } },
  },
})

export interface TimePickerProps extends Omit<
  InputHTMLAttributes<HTMLInputElement>,
  'size' | 'type' | 'value' | 'defaultValue' | 'onChange' | 'min' | 'max' | 'step'
> {
  value?: string
  defaultValue?: string
  onChange?: (value: string) => void
  min?: string
  max?: string
  step?: number
  label?: string
  hint?: string
  error?: string
  size?: 'sm' | 'md' | 'lg'
}

export function TimePicker({
  value,
  defaultValue,
  onChange,
  min,
  max,
  step,
  label,
  hint,
  error,
  size = 'md',
  className,
  id,
  onFocus,
  onBlur,
  ...props
}: TimePickerProps) {
  useSignals()
  const [state, send] = useMachine(machine)
  const inputId =
    id ?? (label ? `cascade-time-picker-${label.toLowerCase().replace(/\s+/g, '-')}` : undefined)

  return (
    <div
      className={cn(styles['wrapper'], className)}
      data-state={error ? 'error' : state.value}
      data-size={size}
    >
      {label && (
        <label className={styles['label']} htmlFor={inputId}>
          {label}
        </label>
      )}
      <input
        id={inputId}
        type="time"
        className={styles['input']}
        value={value}
        defaultValue={defaultValue}
        min={min}
        max={max}
        step={step}
        aria-invalid={error ? true : undefined}
        aria-describedby={error ? `${inputId}-error` : hint ? `${inputId}-hint` : undefined}
        onChange={(e) => onChange?.(e.target.value)}
        onFocus={(e) => {
          send('FOCUS')
          onFocus?.(e)
        }}
        onBlur={(e) => {
          send('BLUR')
          onBlur?.(e)
        }}
        {...props}
      />
      {error && (
        <span id={`${inputId}-error`} className={styles['error']} role="alert">
          {error}
        </span>
      )}
      {!error && hint && (
        <span id={`${inputId}-hint`} className={styles['hint']}>
          {hint}
        </span>
      )}
    </div>
  )
}

@layer cascivo.component {
  .wrapper {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    font-family: var(--cascivo-font-sans);

    &[data-size='sm'] {
      --_height: 2rem;
      --_font: var(--cascivo-text-sm);
      --_px: var(--cascivo-space-3);
    }
    &[data-size='md'] {
      --_height: 2.5rem;
      --_font: var(--cascivo-text-sm);
      --_px: var(--cascivo-space-4);
    }
    &[data-size='lg'] {
      --_height: 3rem;
      --_font: var(--cascivo-text-base);
      --_px: var(--cascivo-space-4);
    }
  }

  .label {
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-snug);
  }

  .input {
    block-size: var(--_height, 2.5rem);
    padding-inline: var(--_px, var(--cascivo-space-4));
    font-family: var(--cascivo-font-sans);
    font-size: var(--_font, var(--cascivo-text-sm));
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    outline: none;
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover:not(:disabled):not(:focus-visible) {
      border-color: var(--cascivo-color-border-strong);
    }

    &:focus-visible {
      border-color: var(--cascivo-color-accent);
      box-shadow: 0 0 0 3px color-mix(in srgb, var(--cascivo-color-accent) 20%, transparent);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
      background-color: var(--cascivo-color-bg-subtle);
    }

    .wrapper[data-state='error'] & {
      border-color: var(--cascivo-color-danger);
    }
  }

  .error {
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-danger);
  }

  .hint {
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-muted);
  }
}
